use std::collections::HashMap;

struct RigidBody {
    id: u32,
    mass: f64,
    position: (f64, f64),
}

impl RigidBody {
    fn new(id: u32, mass: f64, position: (f64, f64)) -> Self {
        RigidBody {
            id,
            mass,
            position,
        }
    }

    fn calculate_momentum(&self) -> (f64, f64) {
        (self.mass * self.position.0, self.mass * self.position.1)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let body1 = RigidBody::new(1, 10.0, (5.0, 2.0));
    let body2 = RigidBody::new(2, 5.0, (1.0, 8.0));

    let momentum1 = body1.calculate_momentum();
    let momentum2 = body2.calculate_momentum();

    println!("Body 1 Momentum: ({:.2}, {:.2})", momentum1.0, momentum1.1);
    println!("Body 2 Momentum: ({:.2}, {:.2})", momentum2.0, momentum2.1);

    Ok(())
}

