use std::collections::HashMap;

#[derive(Debug, Clone)]
pub struct SpecValidator {
    pub metadata: HashMap<String, String>,
}

impl SpecValidator {
    pub fn new() -> Self {
        SpecValidator { metadata: HashMap::new() }
    }

    pub fn load_metadata(&mut self, key: &str, value: &str) {
        self.metadata.insert(key.to_string(), value.to_string());
    }

    pub fn validate_spec(&self, spec_content: &str) -> bool {
        if !self.metadata.contains_key("schema_version") {
            return false;
        }

        let version = self.metadata.get("schema_version").unwrap();
        println!("Validating against schema version: {}", version);

        if spec_content.contains("openapi: 3.0.0") && version == "3.0" {
            true
        } else {
            false
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut validator = SpecValidator::new();
    validator.load_metadata("schema_version", "3.0");

    let good_spec = "openapi: 3.0.0ninfo: { \"name\": \"Test\" }";
    let bad_spec = "openapi: 2.0.0ninfo: { \"name\": \"Old\" }";

    println!("n--- Validation Test 1 ---n");
    if validator.validate_spec(good_spec) {
        println!("Success: The first spec is valid.");
    } else {
        println!("Failure: The first spec is invalid.");
    }

    println!("n--- Validation Test 2 ---n");
    if validator.validate_spec(bad_spec) {
        println!("Success: The second spec is valid.");
    } else {
        println!("Failure: The second spec is invalid (as expected).");
    }

    Ok(())
}

use std::sync::atomic::{AtomicUsize, Ordering};

struct ControlRegisters {
    status_flags: AtomicUsize,
    interrupt_ack: AtomicUsize,
    command_set: AtomicUsize
}

impl ControlRegisters {
    fn new() -> Self {
        ControlRegisters {
            status_flags: AtomicUsize::new(0),
            interrupt_ack: AtomicUsize::new(0),
            command_set: AtomicUsize::new(0)
        }
    }

    fn set_status_bit(&self, mask: usize) -> bool {
        self.status_flags.fetch_or(mask, Ordering::SeqCst) != 0
    }

    fn clear_interrupt_flag(&self, mask: usize) -> usize {
        self.interrupt_ack.fetch_and(!mask, Ordering::SeqCst)
    }

    fn perform_atomic_write_read(&self, write_mask: usize, read_mask: usize) -> (usize, bool) {
        let current_status = self.status_flags.load(Ordering::Acquire);
        let new_value = current_status | write_mask;
        self.status_flags.store(new_value, Ordering::Release);

        let read_result = self.interrupt_ack.load(Ordering::Relaxed) & read_mask;
        (read_result, true)
    }
}

fn main() {
    let registers = ControlRegisters::new();

    println!("Initial Status: {}", registers.status_flags.load(Ordering::SeqCst));

    let write_mask = 0b100;
    let read_mask = 0b001;
    let (result, ok) = registers.perform_atomic_write_read(write_mask, read_mask);

    if ok {
        println!("Successfully updated status register bit and read result: {}", result);
    }

    registers.clear_interrupt_flag(0b10); 
    println!("Cleared interrupt flag.");
}

use std::collections::HashMap;

struct Position {
    pieces: HashMap<String, (i32, i32)>,
}
impl From<Position> for String {
    fn from(pos: Position) -> Self {
        format!("Piece count: {}", pos.pieces.len())
    }
}

fn process_game_state(initial_data: HashMap<String, (i32, i32)>) -> String {
    let position = Position {
        pieces: initial_data.clone()
    };
    String::from(position)
}

fn main() {
    let mut game_pieces = HashMap::new();
    game_pieces.insert("King".to_string(), (0, 4));
    game_pieces.insert("Queen".to_string(), (1, 3));
    game_pieces.insert("Knight".to_string(), (2, 1));

    let result = process_game_state(game_pieces);
    println!("Successfully packaged state: {}", result);
}
